const SHEET\_NAME = "Data\_Cloud\_Query";  
const LIMIT\_ROWS = 100000;

function run\_DataCloudQuery\_JWT\_toSheets() {  
  const token = getAccessTokenByJwt\_();  
  const accessToken = token.access\_token;  
  const instanceUrl = token.instance\_url;

  const sql = \`

SELECT  
    a.ssot\_\_IndividualId\_\_c AS Id,  
    a.ssot\_\_SendtimeEmailAddress\_\_c AS Email,  
    i.ssot\_\_FirstName\_\_c AS FirstName,  
    i.ssot\_\_LastName\_\_c AS LastName,  
    a.ssot\_\_EngagementDateTm\_\_c + interval '9 hour' AS EngagementDateTime,  
    a.ssot\_\_EngagementChannelActionId\_\_c AS ActionName,  
    a.ssot\_\_EmailRecipientSendStatus\_\_c AS SendStatus,  
    c.ssot\_\_Name\_\_c AS EmailElementAPIName,  
    e.ssot\_\_Name\_\_c AS FlowName,  
    d.ssot\_\_VersionNumber\_\_c AS VersionNumber,  
    h.ssot\_\_Name\_\_c AS SegmentName,  
    a.ssot\_\_EngagementActionReasonText\_\_c AS ActionReason,  
    a.ssot\_\_EmailBounceType\_\_c AS BounceType,  
    a.ssot\_\_BounceReasonText\_\_c AS BounceReason,  
    a.ssot\_\_UnsubscribeSourceText\_\_c AS UnsubscribeSource,  
    a.ssot\_\_ResolvedURL\_\_c AS LinkURL,  
    g.ssot\_\_Subject\_\_c AS EmailSubject,  
    g.ssot\_\_FromAddress\_\_c AS FromAddress,  
    g.ssot\_\_MessagePurpose\_\_c AS MessagePurpose  
FROM ssot\_\_EmailEngagement\_\_dlm a  
JOIN ssot\_\_FlowElementRun\_\_dlm b ON a.ssot\_\_FlowElementRunId\_\_c = b.ssot\_\_Id\_\_c  
JOIN ssot\_\_FlowElement\_\_dlm c ON b.ssot\_\_FlowElementId\_\_c = c.ssot\_\_Id\_\_c  
JOIN ssot\_\_FlowVersion\_\_dlm d ON c.ssot\_\_FlowVersionId\_\_c = d.ssot\_\_Id\_\_c  
JOIN ssot\_\_Flow\_\_dlm e ON d.ssot\_\_FlowId\_\_c = e.ssot\_\_Id\_\_c  
JOIN ssot\_\_BulkEmailMessage\_\_dlm g ON a.ssot\_\_BulkEmailMessageId\_\_c = g.ssot\_\_Id\_\_c  
LEFT OUTER JOIN ssot\_\_MarketSegment\_\_dlm h ON g.ssot\_\_MarketSegmentId\_\_c = h.ssot\_\_Id\_\_c  
JOIN ssot\_\_Individual\_\_dlm i ON a.ssot\_\_IndividualId\_\_c = i.ssot\_\_Id\_\_c  
ORDER BY a.ssot\_\_EngagementDateTm\_\_c DESC

LIMIT ${LIMIT\_ROWS}  
\`

.trim();

  const body = postSqlSync\_(instanceUrl, accessToken, sql);

  const headers = extractSelectHeaders\_(sql);

  writeDataCloudResultToSheet\_(SHEET\_NAME, body, headers);  
}

function getAccessTokenByJwt\_() {  
  const now = Math.floor(Date.now() / 1000);  
  const jwtPayload = {  
    iss: CLIENT\_ID,  
    sub: USERNAME,  
    aud: SF\_LOGIN\_URL,  
    exp: now + 180  
  };

  const assertion = buildJwtRs256\_(jwtPayload, PRIVATE\_KEY\_PEM);

  const url = \`${SF\_LOGIN\_URL}/services/oauth2/token\`;  
  const res = UrlFetchApp.fetch(url, {  
    method: "post",  
    payload: {  
      grant\_type: "urn:ietf:params:oauth:grant-type:jwt-bearer",  
      assertion  
    },  
    muteHttpExceptions: true  
  });

  const code = res.getResponseCode();  
  const text = res.getContentText();

  Logger.log("=== JWT token ===");  
  Logger.log("HTTP: " + code);  
  Logger.log("Body(first 2000): " + (text ? text.slice(0, 2000) : ""));

  if (code >= 300) throw new Error(\`JWT token failed: HTTP ${code} / ${text}\`);

  const obj = JSON.parse(text);  
  if (!obj.access\_token || !obj.instance\_url) {  
    throw new Error("Token response missing access\_token/instance\_url: " + text);  
  }  
  return obj;  
}

function buildJwtRs256\_(payloadObj, privateKeyPem) {  
  const header = { alg: "RS256", typ: "JWT" };  
  const encHeader = base64UrlEncode\_(JSON.stringify(header));  
  const encPayload = base64UrlEncode\_(JSON.stringify(payloadObj));  
  const signingInput = \`${encHeader}.${encPayload}\`;

  const signatureBytes = Utilities.computeRsaSha256Signature(signingInput, privateKeyPem);  
  const encSig = base64UrlEncodeBytes\_(signatureBytes);

  return \`${signingInput}.${encSig}\`;  
}

function base64UrlEncode\_(str) {  
  return base64UrlEncodeBytes\_(Utilities.newBlob(str).getBytes());  
}

function base64UrlEncodeBytes\_(bytes) {  
  const b64 = Utilities.base64Encode(bytes);  
  return b64.replace(/\\+/g, "-").replace(/\\//g, "\_").replace(/=+$/g, "");  
}

function postSqlSync\_(instanceUrl, accessToken, sql) {  
  const url = \`${instanceUrl}/services/data/v${API\_VERSION}/ssot/query-sql\`;

  const res = UrlFetchApp.fetch(url, {  
    method: "post",  
    contentType: "application/json",  
    headers: { Authorization: \`Bearer ${accessToken}\` },  
    payload: JSON.stringify({ sql }),  
    muteHttpExceptions: true  
  });

  const code = res.getResponseCode();  
  const text = res.getContentText();

  Logger.log("=== Data Cloud query ===");  
  Logger.log("HTTP: " + code);  
  Logger.log("Body(first 2000): " + (text ? text.slice(0, 2000) : ""));

  if (code >= 300) throw new Error(\`Query failed: HTTP ${code} / ${text}\`);

  const obj = JSON.parse(text);  
  if (!obj.data) throw new Error("No data in response (unexpected format): " + text.slice(0, 2000));  
  return obj;  
}

function extractSelectHeaders\_(sql) {  
  const cleaned = stripSqlComments\_(sql).trim();

  const m = cleaned.match(/\\bselect\\b(\[\\s\\S\]\*?)\\bfrom\\b/i);  
  if (!m) return null;

  const selectPart = m\[1\].trim();  
  if (selectPart === "\*" || /\\\*/.test(selectPart)) return null;

  const items = splitByCommaOutsideParens\_(selectPart);

  const headers = items.map(expr => headerFromSelectItem\_(expr)).filter(Boolean);  
  return headers.length ? headers : null;  
}

function stripSqlComments\_(sql) {  
  return sql.replace(/\\/\\\*\[\\s\\S\]\*?\\\*\\//g, "").replace(/--.\*$/gm, "");  
}

function splitByCommaOutsideParens\_(s) {  
  const out = \[\];  
  let buf = "";  
  let depth = 0;

  for (let i = 0; i < s.length; i++) {  
    const ch = s\[i\];  
    if (ch === "(") depth++;  
    if (ch === ")") depth = Math.max(0, depth - 1);

    if (ch === "," && depth === 0) {  
      out.push(buf.trim());  
      buf = "";  
    } else {  
      buf += ch;  
    }  
  }

  if (buf.trim()) out.push(buf.trim());  
  return out;  
}

function headerFromSelectItem\_(item) {  
  const t = item.trim().replace(/\\s+/g, " ");

  const asMatch = t.match(/\\s+as\\s+(\[A-Za-z0-9\_\]+)$/i);  
  if (asMatch) return asMatch\[1\];

  const parts = t.split(" ");  
  if (parts.length >= 2) {  
    const last = parts\[parts.length - 1\];  
    const beforeLast = parts.slice(0, -1).join(" ");  
    if (!/\[().\]/.test(last) && /\[().\]/.test(beforeLast) === false) {  
      return last;  
    }  
  }

  const col = t.replace(/^.\*\\./, "");  
  return col;  
}

function writeDataCloudResultToSheet\_(sheetName, body, explicitHeaders) {  
  const ss = SpreadsheetApp.getActiveSpreadsheet();  
  const sheet = ss.getSheetByName(sheetName) || ss.insertSheet(sheetName);  
  sheet.clearContents();

  const data = body.data;  
  if (!Array.isArray(data) || data.length === 0) {  
    sheet.getRange(1, 1).setValue("No rows.");  
    return;  
  }

  if (Array.isArray(data\[0\])) {  
    const colCount = data\[0\].length;

    const headers =  
      Array.isArray(explicitHeaders) && explicitHeaders.length === colCount  
        ? explicitHeaders  
        : Array.from({ length: colCount }, (\_, i) => \`col\_${i + 1}\`);

    const CHUNK = 5000;  
    sheet.getRange(1, 1, 1, headers.length).setValues(\[headers\]);

    for (let i = 0; i < data.length; i += CHUNK) {  
      const chunk = data.slice(i, i + CHUNK);  
      sheet.getRange(2 + i, 1, chunk.length, headers.length).setValues(chunk);  
    }  
    return;  
  }

  sheet.getRange(1, 1).setValue("Unexpected data format.");  
  sheet.getRange(2, 1).setValue(JSON.stringify(body).slice(0, 5000));  
}

